package be.schaubroeck.lpb.rkm.rekenmotor.service;

import be.schaubroeck.lpb.tools.Admin;
import be.schaubroeck.lpb.tools.ProcesService;
import be.schaubroeck.lpb.tools.service.GewaarborgdLoonSupplementImportService;
import be.schaubroeck.lpb.tools.service.OpdrachtService;
import be.schaubroeck.lpb.tools.service.OverdrachtOpdrachtDoelService;
import be.schaubroeck.lpb.tools.service.PersoonService;
import be.schaubroeck.lpb.tools.util.InitializeAdmin;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.security.core.context.SecurityContextHolder;

import java.io.File;
import java.util.concurrent.ExecutorService;

public class StandaardGewaarborgdLoonSupplementImportBestandService implements GewaarborgdLoonSupplementImportBestandService {

    protected String uploadDirectory = "/var/webapps/lima/rkm/gewaarborgdloon/upload";

    @Autowired
    protected PersoonService persoonService;

    @Autowired
    protected OpdrachtService opdrachtService;

    @Autowired
    protected OverdrachtOpdrachtDoelService overdrachtOpdrachtDoelService;

    @Autowired
    protected GewaarborgdLoonSupplementImportService gewaarborgdLoonSupplementImportService;

    @Autowired
    private ExecutorService procesExecutor;

    @Override
    public String getUploadDirectory() {
        return uploadDirectory;
    }

    @Override
    public void setUploadDirectory(String uploadDirectory) {
        if (uploadDirectory != null) {
            this.uploadDirectory = uploadDirectory.endsWith(File.separator) ? uploadDirectory : (uploadDirectory + File.separator);
        }
    }

    @InitializeAdmin
    public String importFile(Admin admin, String uploadDirBaseName, File file) {
        if (SecurityContextHolder.getContext().getAuthentication() != null) {
            String procesId = ProcesService.getProcesId();
            GewaarborgdLoonSupplementImportBestandProces proces = new GewaarborgdLoonSupplementImportBestandProces(admin,
                    file,
                    persoonService,
                    opdrachtService,
                    overdrachtOpdrachtDoelService,
                    gewaarborgdLoonSupplementImportService);
            proces.init(procesId);
            procesExecutor.submit(proces); //roept proces.run() aan, dat op zich onderstaande overload van importFile(...) aanroept
            return proces.getId();
        }

        return null;
    }

}
